#include <stdio.h>
int main() {
    int T, N;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        if (scanf("%d", &N) != 1) return 0;
        unsigned long long result = 1ULL;
        if (N == 0) {
            printf("1\n");
            continue;
        }
        int i = 1;
        do {
            result *= (unsigned long long)i;
            i++;
        } while (i <= N);
        printf("%llu\n", result);
    }
    return 0;
}

